const defaultScriptTimeout = 500 * time.Millisecond

func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Inject order fields into the global scope
	for key, value := range order {
		vm.Set(key, value)
	}

	// Set up a context with a timeout to prevent DoS attacks (infinite loops)
	ctx, cancel := context.WithTimeout(context.Background(), defaultScriptTimeout)
	defer cancel()

	// Channel to signal script completion
	done := make(chan struct{})
	var result goja.Value
	var err error

	// Execute script in a goroutine to allow interruption
	go func() {
		defer close(done)
		// RunString doesn't accept context directly, so we rely on Interrupt()
		result, err = vm.RunString(script)
	}()

	// Wait for script completion or timeout
	select {
	case <-done:
		// Script finished successfully within the time limit
