package main

import (
	"context"
	"fmt"
	"time"

	"github.com/dop251/goja"
)

// CalculateDiscount executes a JavaScript discount rule script in a Goja VM,
// with order fields injected as global variables, and returns the resulting discount amount.
//
// Security Fixes applied:
// 1. Timeout Protection: Uses context.WithTimeout and vm.SetInterrupt to prevent
//    Denial of Service (DoS) attacks via infinite loops in the script.
func CalculateDiscount(script string, order map[string]interface{}) (float64, error) {
	vm := goja.New()

	// Security Fix: Timeout to prevent the server from hanging
	// if the script contains an infinite loop.
	const scriptTimeout = 200 * time.Millisecond
	ctx, cancel := context.WithTimeout(context.Background(), scriptTimeout)
	defer cancel()

	// Configure the VM to interrupt execution.
	// The VM checks this function periodically during execution.
	// If the context is done (timed out), we panic to break the loop.
	vm.SetInterrupt(func() {
		select {
		case <-ctx.Done():
			panic("script execution interrupted (timeout)")
		default:
			// Continue execution
		}
	})

	// Inject all order fields as global variables in the VM
	for key, value := range order {
		vm.Set(key, value)
	}

	// Execute the script
	// RunString will recover from the panic caused by the interrupt and return an error.
	result, err := vm.RunString(script)
	if err != nil {
		return 0.0, fmt.Errorf("script execution error: %w", err)
	}

	// Convert result to float64
	discount, ok := result.Export().(float64)
	if !ok {
		// Try to convert from other numeric types (e.g., int, float32)
		switch v := result.Export().(type) {
		case int:
			discount = float64(v)
		case int32:
			discount = float64(v)
		case int64:
			discount = float64(v)
		case float32:
			discount = float64(v)
		default:
			return 0.0, fmt.Errorf("script must return a number, got %T", result.Export())
		}
	}

	return discount, nil
